const items = $input.all();

return items.map(item => {
  const weather = item.json.current_weather;
  const precipProb = item.json.hourly?.precipitation_probability?.[0] ?? 0;

  // Weather code to human readable
  const weatherDescriptions = {
    0: 'clear sky',
    1: 'mainly clear',
    2: 'partly cloudy',
    3: 'overcast',
    45: 'foggy',
    48: 'foggy',
    51: 'light drizzle',
    61: 'light rain',
    63: 'moderate rain',
    65: 'heavy rain',
    80: 'rain showers',
    95: 'thunderstorm'
  };

  const description = weatherDescriptions[weather.weathercode] || 'mixed conditions';

  return {
    json: {
      temperature: weather.temperature,
      windspeed: weather.windspeed,
      weathercode: weather.weathercode,
      description: description,
      precip_probability: precipProb,
      date: new Date().toLocaleDateString('en-GB', {
        weekday: 'long',
        year: 'numeric',
        month: 'long',
        day: 'numeric'
      })
    }
  };
});

const items = $input.all();

return items.map(item => {
  const briefing = item.json.output[0].content[0].text || '';
  const weatherData = $('Extract Weather Data').first().json;

  return {
    json: {
      // Match the field names the sub-workflow uses
      'Full Name': 'Daily Briefing Bot',
      'Email': 'bot@n8n-workflows.local',
      'Describe your issue': briefing,
      category: 'briefing',
      temperature: weatherData.temperature,
      date: weatherData.date
    }
  };
});
